package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.api.management.ManagedAttribute;
import org.apache.camel.api.management.ManagedResource;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * The FIX producer
 */
@ManagedResource(description = "Managed FixProducer")
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);
    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            // Get the FIX message from the exchange body
            String fixMessage = exchange.getIn().getBody(String.class);

            if (LOG.isDebugEnabled()) {
                LOG.debug("Sending FIX message: {} for session: {}", fixMessage, endpoint.getSessionID());
            }

            // Set the session ID header if not already set
            String sessionId = exchange.getIn().getHeader(FixConstants.HEADER_FIX_SESSION_ID, String.class);
            if (sessionId == null) {
                exchange.getIn().setHeader(FixConstants.HEADER_FIX_SESSION_ID, endpoint.getSessionID());
            }

            // Process the message asynchronously
            // In a real implementation, this would send the FIX message via the FIX engine
            // For now, we just mark it as processed
            callback.done(true);
            return true;

        } catch (Exception e) {
            exchange.setException(e);
            callback.done(true);
            return true;
        }
    }

    @ManagedAttribute(description = "Session ID")
    public String getSessionID() {
        return endpoint.getSessionID();
    }
}

