package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.Processor;
import org.apache.camel.api.management.ManagedAttribute;
import org.apache.camel.api.management.ManagedResource;
import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * The FIX consumer
 */
@ManagedResource(description = "Managed FixConsumer")
public class FixConsumer extends DefaultConsumer {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);
    private final FixEndpoint endpoint;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        if (LOG.isDebugEnabled()) {
            LOG.debug("Starting FixConsumer for session: {}", endpoint.getSessionID());
        }

        // In a real implementation, this would initialize and start the FIX acceptor
        // or initiator session based on the configuration
        getComponent().addConsumer(endpoint, this);
    }

    @Override
    protected void doStop() throws Exception {
        if (LOG.isDebugEnabled()) {
            LOG.debug("Stopping FixConsumer for session: {}", endpoint.getSessionID());
        }

        // In a real implementation, this would stop and shutdown the FIX session
        getComponent().removeConsumer(endpoint, this);

        super.doStop();
    }

    @Override
    public FixComponent getComponent() {
        return endpoint.getComponent();
    }

    /**
     * Process a FIX message received from the FIX engine
     */
    public void processFixMessage(String messageType, String rawMessage) {
        final Exchange exchange = createExchange(false);

        try {
            exchange.getIn().setBody(rawMessage);
            exchange.getIn().setHeader(FixConstants.HEADER_FIX_MESSAGE_TYPE, messageType);
            exchange.getIn().setHeader(FixConstants.HEADER_FIX_SESSION_ID, endpoint.getSessionID());

            // Get additional headers from configuration if available
            if (endpoint.getSenderCompID() != null) {
                exchange.getIn().setHeader(FixConstants.HEADER_FIX_SENDER_COMP_ID, endpoint.getSenderCompID());
            }
            if (endpoint.getTargetCompID() != null) {
                exchange.getIn().setHeader(FixConstants.HEADER_FIX_TARGET_COMP_ID, endpoint.getTargetCompID());
            }

            if (LOG.isTraceEnabled()) {
                LOG.trace("FixConsumer received message type {} for session {}", messageType, endpoint.getSessionID());
            }

            if (isRunAllowed()) {
                // use default consumer callback
                AsyncCallback cb = defaultConsumerCallback(exchange, false);
                getAsyncProcessor().process(exchange, cb);
            }

        } catch (Exception e) {
            exchange.setException(e);
            LOG.warn("Error processing FIX message", e);
        } finally {
            releaseExchange(exchange, false);
        }
    }

    @ManagedAttribute(description = "Session ID")
    public String getSessionID() {
        return endpoint.getSessionID();
    }
}

